const files = $input.first().json.files || [];
const folders = files.map(f => ({
  id: f.id,
  name: f.name,
  parents: f.parents || []
}));
return [{ json: { folders } }];

const data = $input.first().json;
return [{ json: {
  id: data.id,
  name: data.name,
  parents: data.parents || []
} }];
